={{ (() => {
  const compact = (value) =>
    String(value ?? '')
      .replace(/\r\n/g, '\n')
      .split('\n')
      .map((line) => line.trimEnd())
      .join('\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();

  const text = compact(typeof $json.messageText === 'string' ? $json.messageText : '');
  const summaryUrl = compact(typeof $json.summaryUrl === 'string' ? $json.summaryUrl : '');

  if (!summaryUrl) return text;

  const hasUrl = /https?:\/\/\S+/i.test(text);
  if (hasUrl) return text;

  return compact([
    text,
    'Para concluir seu agendamento com segurança, acesse este link: ' + summaryUrl,
  ].filter(Boolean).join('\n\n'));
})() }}

