  if (typeof output === 'object' && output !== null) {
    const url = typeof output.summaryUrl === 'string' ? output.summaryUrl.trim() : '';
    if (url && output.ok !== false) return url;

    const nestedUrl = typeof output?.data?.summaryUrl === 'string' ? output.data.summaryUrl.trim() : '';
    if (nestedUrl && output?.data?.ok !== false) return nestedUrl;
  }

  return '';
})() }}

parameters.jsCode:
const now = new Date();
const fortalezaTime = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Fortaleza',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false,
}).format(now);

const isoFormatted = now.toISOString();
const items = $input.all();

const isInboundTextMessage = (payload) => {
  const message = payload?.messages?.[0];
  if (!message || typeof message !== 'object') return false;

  const messageType = String(message.type ?? '').toLowerCase();
  const body = typeof message?.text?.body === 'string' ? message.text.body.trim() : '';
  const from = typeof message.from === 'string' ? message.from.trim() : '';

  // Processa apenas mensagem de texto do paciente.
  if (!from) return false;
  if (!body) return false;
  return messageType === 'text';
};

return items
  .filter((item) => isInboundTextMessage(item.json))
  .map((item) => ({
    json: {
      ...item.json,
      currentDateTime: fortalezaTime,
      currentDateTimeISO: isoFormatted,
      timezone: 'America/Fortaleza',
    },
  }));
